import React from 'react';
import "../styles/FooterStyles.css";

const Footer = () => {
    return (
        <div className="Footer">
            <div className="FooterText">
                Created and designed by: Gustavo Bautista
                <br />
                &copy; Bug Trackerly
            </div>
        </div>
    );
};

export default Footer;
